export type CartEvent =
  | { type: 'cart.item-added'; sku: string }
  | { type: 'cart.checked-out'; orderId: string };

export type NotificationEvent =
  | { type: 'notification.queued'; message: string }
  | { type: 'notification.dismissed'; id: string };

@Injectable({ providedIn: 'root' })
export class EventBus {
  private events = new Subject<AppEvent>();
  publish(event: AppEvent) { this.events.next(event); }
  listen() { return this.events.asObservable(); }
}

@Injectable()
export class CartAnalyticsSubscriber {
  constructor(bus: EventBus, analytics: Analytics) {
    bus.listen().pipe(filter(isCartItemAdded)).subscribe((event) => analytics.track(event));
  }
}

@Injectable()
export class HeaderCounterSubscriber {
  count = signal(0);
  handle(event: CartEvent) { if (event.type === 'cart.item-added') this.count.update((v) => v + 1); }
}

export function addToCart(product: Product, bus: EventBus) {
  bus.publish({ type: 'cart.item-added', sku: product.sku });
}
